solution_code:
#include <iostream>

int larger(int a, int b);

int main()
{
    int a;
    int b;
    std::cin >> a >> b;
    std::cout << "Larger: " << larger(a, b) << "\n";
    return 0;
}

int larger(int a, int b)
{
    return (a + b + (a - b)) / 2;
}

